#include<bits/stdc++.h>
using namespace std;
int n,a[1000010],sum[1000010],l[1000010],r[1000010];
void dfs(int x)
{
    sum[x]=1;
    if(l[x]!=-1)
    {
        dfs(l[x]);
        sum[x]+=sum[l[x]];
    }
    if(r[x]!=-1)
    {
        dfs(r[x]);
        sum[x]+=sum[r[x]];
    }
}
bool check(int x,int y)
{
    if(x==-1&&y==-1)
    {
        return true;
    }
    if(x==-1||y==-1)
    {
        return false;
    }
    if(a[x]!=a[y]||sum[x]!=sum[y])
    {
        return false;
    }
    return check(l[x],r[y])&&check(r[x],l[y]);
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&l[i],&r[i]);
    }
    dfs(1);
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        if(check(l[i],r[i]))
        {
            ans=max(ans,sum[i]);
        }
    }
    printf("%d",ans);
    return 0;
}
